prompt.input:
// Code to review would be inserted here
function processUserData(userData) {
  const query = "SELECT * FROM users WHERE id = " + userData.id;
  return db.execute(query);
}

output_contract.schema:
{
  "summary": {
    "total_issues": <integer>,
    "critical": <integer>,
    "warning": <integer>,
    "suggestion": <integer>,
    "overall_assessment": "<string: APPROVE | REQUEST_CHANGES | NEEDS_DISCUSSION>"
  },
  "issues": [
    {
      "id": "<string: unique identifier like SEC-001>",
      "severity": "<string: critical | warning | suggestion>",
      "category": "<string: security | performance | maintainability | correctness>",
      "line_start": <integer>,
      "line_end": <integer>,
      "title": "<string: brief issue title, max 80 chars>",
      "description": "<string: detailed explanation>",
      "suggestion": "<string: how to fix, or null if unclear>",
      "code_snippet": "<string: the problematic code, or null>"
    }
  ],
  "positive_observations": [
    "<string: things done well, max 3 items>"
  ]
}

output_contract.example_output:
{
  "summary": {
    "total_issues": 1,
    "critical": 1,
    "warning": 0,
    "suggestion": 0,
    "overall_assessment": "REQUEST_CHANGES"
  },
  "issues": [
    {
      "id": "SEC-001",
      "severity": "critical",
      "category": "security",
      "line_start": 3,
      "line_end": 3,
      "title": "SQL Injection vulnerability via string concatenation",
      "description": "User input is directly concatenated into SQL query without sanitization or parameterization, allowing arbitrary SQL execution.",
